&reftitle.returnvalues;

 Returns the number of buffered log entries as an int.
 Returns 0 when buffering is disabled.

  &reftitle.examples;

   SeasLog::getBufferCount example


<?php

SeasLog::info('log info test');
SeasLog::debug('log debug test');

var_dump(SeasLog::getBufferCount());

?>


